/**
 * Acceptance tests: Sidebar + Detail Layout Data Preparation (v2)
 *
 * Validates pure functions that prepare data for the sidebar display
 * (sparkline buffers, current values, selection state) and detail pane
 * (aggregate graph visibility, per-session grid layout, stats content,
 * session table content).
 *
 * Driving ports: categoryConfig (aggregate applicability), chartRenderer
 * (sparkline prep), crossSessionAggregator (session breakdown)
 *
 * These tests exercise data preparation logic, not React rendering.
 *
 * Traces to: ADR-007 "Sidebar-Detail Layout", ADR-009 "Aggregate
 * Applicability", Design spec Sections 1-4, US-PM-001, US-PM-002
 */

import { describe, it, expect } from "vitest";

// Driving ports
import {
  METRIC_CATEGORIES,
  getCategoryById,
} from "../../../src/plugins/norbert-usage/domain/categoryConfig";

import {
  aggregateAcrossSessions,
} from "../../../src/plugins/norbert-usage/domain/crossSessionAggregator";

import {
  createInitialMetrics,
  type SessionMetrics,
} from "../../../src/plugins/norbert-usage/domain/metricsAggregator";

// ---------------------------------------------------------------------------
// Helper
// ---------------------------------------------------------------------------

const createSessionSnapshot = (
  overrides: Partial<SessionMetrics> & { sessionId: string },
): SessionMetrics => ({
  ...createInitialMetrics(overrides.sessionId),
  ...overrides,
});

// ---------------------------------------------------------------------------
// WALKING SKELETON: User selects a category and sees scoped detail
// Traces to: ADR-007, US-PM-001, Design spec Section 1
// ---------------------------------------------------------------------------

describe("User selects a metric category and sees category-scoped detail pane", () => {
  it("selecting tokens category shows aggregate graph and category-specific stats", () => {
    // Given Ravi has 3 active sessions
    const sessions: ReadonlyArray<SessionMetrics> = [
      createSessionSnapshot({ sessionId: "refactor-auth", burnRate: 312 }),
      createSessionSnapshot({ sessionId: "migrate-db", burnRate: 185 }),
      createSessionSnapshot({ sessionId: "test-coverage", burnRate: 30 }),
    ];

    // When the tokens category is selected
    const selectedCategory = getCategoryById("tokens");
    const aggregate = aggregateAcrossSessions(sessions);

    // Then the category is aggregate-applicable (tokens supports aggregation)
    expect(selectedCategory.aggregateApplicable).toBe(true);
    // And aggregate data is available for the detail pane
    expect(aggregate.totalTokenRate).toBe(527);
    expect(aggregate.sessionCount).toBe(3);
  });
});

// ---------------------------------------------------------------------------
// FOCUSED SCENARIOS: Aggregate Graph Visibility
// Traces to: ADR-009, Design spec Section 1 "Aggregate Graph Applicability"
// ---------------------------------------------------------------------------

describe("Detail pane shows aggregate graph for aggregatable categories", () => {
  it("tokens category has aggregate graph visible", () => {
    // Given the tokens category is selected
    const category = getCategoryById("tokens");

    // When checking whether to show the aggregate graph
    // Then the aggregate graph should be shown
    expect(category.aggregateApplicable).toBe(true);
  });

  it("cost category has aggregate graph visible", () => {
    // Given the cost category is selected
    const category = getCategoryById("cost");

    // Then the aggregate graph should be shown
    expect(category.aggregateApplicable).toBe(true);
  });

  it("agents category has aggregate graph visible", () => {
    // Given the agents category is selected
    const category = getCategoryById("agents");

    // Then the aggregate graph should be shown
    expect(category.aggregateApplicable).toBe(true);
  });
});

describe("Detail pane omits aggregate graph for context category", () => {
  it("context category skips aggregate graph and shows per-session as primary", () => {
    // Given the context category is selected
    const category = getCategoryById("context");

    // When checking whether to show the aggregate graph
    // Then the aggregate graph is omitted (context is not aggregatable)
    expect(category.aggregateApplicable).toBe(false);
    // And per-session graphs become the primary display
  });
});

// ---------------------------------------------------------------------------
// FOCUSED SCENARIOS: Per-Session Grid Visibility Rules
// Traces to: Design spec Section 2 "Per-Session Graphs"
// ---------------------------------------------------------------------------

describe("Per-session grid hidden when only one session is active", () => {
  it("single session means per-session grid is not needed", () => {
    // Given Elena has only 1 active session
    const sessions: ReadonlyArray<SessionMetrics> = [
      createSessionSnapshot({ sessionId: "user-auth", burnRate: 280 }),
    ];

    // When the aggregate is computed
    const aggregate = aggregateAcrossSessions(sessions);

    // Then session count is 1 (view hides per-session grid)
    expect(aggregate.sessionCount).toBe(1);
  });
});

describe("Per-session grid shown when two or more sessions are active", () => {
  it("multiple sessions trigger per-session graph grid", () => {
    // Given Ravi has 3 active sessions
    const sessions: ReadonlyArray<SessionMetrics> = [
      createSessionSnapshot({ sessionId: "s1", burnRate: 100 }),
      createSessionSnapshot({ sessionId: "s2", burnRate: 200 }),
      createSessionSnapshot({ sessionId: "s3", burnRate: 300 }),
    ];

    // When the aggregate is computed
    const aggregate = aggregateAcrossSessions(sessions);

    // Then session count is > 1 (view shows per-session grid)
    expect(aggregate.sessionCount).toBeGreaterThan(1);
    // And per-session breakdown lists all sessions
    expect(aggregate.sessions).toHaveLength(3);
  });
});

// D5: Session table column tests moved to category-configuration.test.ts
// where they assert specific column names instead of just length >= 3.

// ---------------------------------------------------------------------------
// FOCUSED SCENARIOS: Sidebar Current Value Display
// Traces to: Design spec Section 1 "Left Sidebar", data-models.md "Sidebar Display Data"
// ---------------------------------------------------------------------------

describe("Sidebar shows current value for each category from latest sample", () => {
  it("token rate formatted and displayed in sidebar row", () => {
    // Given the tokens category and a current aggregate rate of 527 tok/s
    const tokens = getCategoryById("tokens");

    // When the current value is formatted
    const formatted = tokens.formatValue(527);

    // Then the sidebar displays "527 tok/s"
    expect(formatted).toBe("527 tok/s");
  });

  it("cost rate formatted and displayed in sidebar row", () => {
    // Given the cost category and a current cost rate of 0.005 $/s
    const cost = getCategoryById("cost");

    // When the current value is formatted
    const formatted = cost.formatValue(0.005);

    // Then the sidebar displays the rate as $/min
    expect(formatted).toContain("/min");
  });
});

// ---------------------------------------------------------------------------
// ERROR SCENARIOS: Empty State
// Traces to: US-PM-001 scenario 3
// ---------------------------------------------------------------------------

describe("No sessions active produces zero aggregate for all categories", () => {
  it("all category values are zero when no sessions exist", () => {
    // Given Marcus has no active Claude Code sessions
    const sessions: ReadonlyArray<SessionMetrics> = [];

    // When aggregate metrics are computed
    const aggregate = aggregateAcrossSessions(sessions);

    // Then all values are zero
    expect(aggregate.totalTokenRate).toBe(0);
    expect(aggregate.totalCostRate).toBe(0);
    expect(aggregate.totalActiveAgents).toBe(0);
    expect(aggregate.sessionCount).toBe(0);
  });
});

describe("Session ends while viewing detail pane", () => {
  it("aggregate recomputes correctly when a session is removed", () => {
    // Given 3 sessions and one ends
    const allSessions: ReadonlyArray<SessionMetrics> = [
      createSessionSnapshot({ sessionId: "s1", burnRate: 200 }),
      createSessionSnapshot({ sessionId: "ending", burnRate: 150 }),
      createSessionSnapshot({ sessionId: "s3", burnRate: 100 }),
    ];

    // When session "ending" is removed from the active set
    const remaining = allSessions.filter(s => s.sessionId !== "ending");
    const aggregate = aggregateAcrossSessions(remaining);

    // Then aggregate reflects only the remaining sessions
    expect(aggregate.totalTokenRate).toBe(300);
    expect(aggregate.sessionCount).toBe(2);
  });
});

// ---------------------------------------------------------------------------
// ERROR SCENARIOS: Context Data Unavailable in Detail Pane
// Traces to: US-PM-005 scenario 3
// ---------------------------------------------------------------------------

describe("Session with zero context data shows safely in detail pane", () => {
  it("zero max tokens signals data unavailability", () => {
    // Given a session where context data is not available
    const session = createSessionSnapshot({
      sessionId: "no-context",
      contextWindowPct: 0,
      contextWindowMaxTokens: 0,
    });

    // When the context category is selected
    // Then the session's context value is 0
    expect(session.contextWindowPct).toBe(0);
    // And max tokens being 0 signals the view to show "Data unavailable"
    expect(session.contextWindowMaxTokens).toBe(0);
  });
});

describe("New session added while viewing detail pane", () => {
  it("aggregate updates correctly when a new session appears", () => {
    // Given 2 sessions and the user is viewing the tokens detail
    const existingSessions: ReadonlyArray<SessionMetrics> = [
      createSessionSnapshot({ sessionId: "s1", burnRate: 250 }),
      createSessionSnapshot({ sessionId: "s2", burnRate: 150 }),
    ];

    // When a new session starts
    const updatedSessions: ReadonlyArray<SessionMetrics> = [
      ...existingSessions,
      createSessionSnapshot({ sessionId: "new-session", burnRate: 80 }),
    ];

    const aggregate = aggregateAcrossSessions(updatedSessions);

    // Then the aggregate includes the new session
    expect(aggregate.sessionCount).toBe(3);
    expect(aggregate.totalTokenRate).toBe(480);
  });
});

describe("All sessions idle shows zero rates across all categories", () => {
  it("zero burn rates produce zero aggregate for all aggregatable categories", () => {
    // Given 3 sessions all idle (zero burn rate)
    const sessions: ReadonlyArray<SessionMetrics> = [
      createSessionSnapshot({ sessionId: "idle-1", burnRate: 0, activeAgentCount: 0 }),
      createSessionSnapshot({ sessionId: "idle-2", burnRate: 0, activeAgentCount: 0 }),
      createSessionSnapshot({ sessionId: "idle-3", burnRate: 0, activeAgentCount: 0 }),
    ];

    // When aggregate is computed
    const aggregate = aggregateAcrossSessions(sessions);

    // Then all rates are zero but session count is 3
    expect(aggregate.totalTokenRate).toBe(0);
    expect(aggregate.totalCostRate).toBe(0);
    expect(aggregate.totalActiveAgents).toBe(0);
    expect(aggregate.sessionCount).toBe(3);
  });
});

describe("Session breakdown sorted by primary metric for each category", () => {
  it("sessions sorted by token rate descending when tokens selected", () => {
    // Given sessions with rates 30, 312, 185 (unsorted)
    const sessions: ReadonlyArray<SessionMetrics> = [
      createSessionSnapshot({ sessionId: "low", burnRate: 30 }),
      createSessionSnapshot({ sessionId: "high", burnRate: 312 }),
      createSessionSnapshot({ sessionId: "mid", burnRate: 185 }),
    ];

    // When aggregate is computed
    const aggregate = aggregateAcrossSessions(sessions);

    // Then sessions are sorted: 312, 185, 30
    expect(aggregate.sessions[0].tokenRate).toBe(312);
    expect(aggregate.sessions[1].tokenRate).toBe(185);
    expect(aggregate.sessions[2].tokenRate).toBe(30);
  });
});

// ---------------------------------------------------------------------------
// BOUNDARY SCENARIOS: Category Selection State
// ---------------------------------------------------------------------------

describe("Default category selection is tokens", () => {
  it("first category in the configuration is tokens", () => {
    // Given the category configuration
    // When the first category is checked
    // Then it is tokens (default selection for initial load)
    expect(METRIC_CATEGORIES[0].id).toBe("tokens");
  });
});

// ---------------------------------------------------------------------------
// PROPERTY-SHAPED SCENARIOS
// Traces to: Design spec -- all 4 categories rendered in sidebar
// ---------------------------------------------------------------------------

describe("@property: every category has all required sidebar display fields", () => {
  it("every category has label, color, and formatValue function", () => {
    // Given the full category configuration
    for (const category of METRIC_CATEGORIES) {
      // When required sidebar fields are checked
      // Then all fields are present and valid
      expect(category.label).toBeTruthy();
      expect(category.color).toMatch(/^#[0-9a-fA-F]{6}$/);
      expect(typeof category.formatValue).toBe("function");
    }
  });
});

// ---------------------------------------------------------------------------
// WIRING: Performance Monitor v2 renders in the performance-monitor view slot
// Traces to: 05-01, US-PM-001
// ---------------------------------------------------------------------------

describe("Performance Monitor v2 renders in the performance-monitor view slot", () => {
  // D4: Removed "multiSessionStore exposes appendSessionSample" and
  // "hook processor accepts appendSessionSample in its deps" tests --
  // they only asserted typeof === 'function' (compile-time guarantees).
  // Behavioral wiring is covered by per-session-category-buffers tests.

  it("v1 view files PMAggregateGrid and PMSessionDetail are removed", async () => {
    // Given the v2 Performance Monitor replaces v1 views
    // When checking for v1 module existence
    const fs = await import("fs");
    const path = await import("path");
    const viewsDir = path.resolve(__dirname, "../../../src/plugins/norbert-usage/views");

    // Then v1 files no longer exist
    expect(fs.existsSync(path.join(viewsDir, "PMAggregateGrid.tsx"))).toBe(false);
    expect(fs.existsSync(path.join(viewsDir, "PMSessionDetail.tsx"))).toBe(false);
  });

  it("v1 types PMViewMode, AgentMetrics, SessionDetailData are removed from types.ts", async () => {
    // Given the v2 PM uses new domain types
    // When reading the types module source
    const fs = await import("fs");
    const path = await import("path");
    const typesPath = path.resolve(__dirname, "../../../src/plugins/norbert-usage/domain/types.ts");
    const source = fs.readFileSync(typesPath, "utf-8");

    // Then the v1-only types are no longer exported
    expect(source).not.toContain("export type PMViewMode");
    expect(source).not.toContain("export interface AgentMetrics");
    expect(source).not.toContain("export interface SessionDetailData");
  });
});

/**
 * Acceptance tests: Per-Session Per-Category Time-Series Buffers (v2)
 *
 * Validates the MultiSessionStore extension: per-session per-category
 * ring buffers, aggregate buffer computation, subscriber notification,
 * and the aggregate applicability rule (context has no aggregate).
 *
 * Driving ports: extended MultiSessionStore adapter
 * These tests exercise the adapter boundary with real internal domain
 * functions (ring buffers), mocking nothing internal.
 *
 * Traces to: ADR-008 "Per-Session Per-Category Time-Series Buffers",
 * ADR-009 "Aggregate Applicability by Category",
 * architecture-design.md "MultiSessionStore Extension",
 * data-models.md "Extended MultiSessionStore Interface"
 */

import { describe, it, expect } from "vitest";

// Driving port: extended MultiSessionStore (adapter boundary)
// These imports will resolve once the module is extended.
import {
  createMultiSessionStore,
  type MultiSessionStore,
  type CategorySampleInput,
} from "../../../src/plugins/norbert-usage/adapters/multiSessionStore";

import type { MetricCategoryId } from "../../../src/plugins/norbert-usage/domain/categoryConfig";

// Hook processor: driving port for the category sample feeding pipeline
import { createHookProcessor, type HookProcessorDeps } from "../../../src/plugins/norbert-usage/hookProcessor";
import type { SessionMetrics } from "../../../src/plugins/norbert-usage/domain/types";
import { createInitialMetrics } from "../../../src/plugins/norbert-usage/domain/metricsAggregator";
import { DEFAULT_PRICING_TABLE } from "../../../src/plugins/norbert-usage/domain/pricingModel";

// ---------------------------------------------------------------------------
// WALKING SKELETON: User sees per-session graphs update with new data
// Traces to: ADR-008, US-PM-002 per-session graphs
// ---------------------------------------------------------------------------

describe("User sees per-session metric graphs update as events arrive", () => {
  it("appending a sample to a session creates per-category time-series data", () => {
    // Given a multi-session store with one active session "refactor-auth"
    const store = createMultiSessionStore();
    store.addSession("refactor-auth");

    // When a category sample is appended for that session
    store.appendSessionSample("refactor-auth", {
      tokens: 312,
      cost: 0.003,
      agents: 2,
      context: 45,
    });

    // Then the session's token buffer contains the sample
    const tokenBuffer = store.getSessionBuffer("refactor-auth", "tokens");
    expect(tokenBuffer).toBeDefined();
    expect(tokenBuffer!.samples.length).toBeGreaterThan(0);

    // And the session's context buffer also contains the sample
    const contextBuffer = store.getSessionBuffer("refactor-auth", "context");
    expect(contextBuffer).toBeDefined();
    expect(contextBuffer!.samples.length).toBeGreaterThan(0);
  });
});

// ---------------------------------------------------------------------------
// FOCUSED SCENARIOS: Per-Session Buffer Operations
// Traces to: ADR-008, data-models.md PerSessionCategoryBuffers
// ---------------------------------------------------------------------------

describe("Each session maintains independent buffers per category", () => {
  it("two sessions have separate token buffers with different values", () => {
    // Given two active sessions with different token rates
    const store = createMultiSessionStore();
    store.addSession("session-a");
    store.addSession("session-b");

    // When different samples are appended to each session
    store.appendSessionSample("session-a", { tokens: 500, cost: 0.005, agents: 1, context: 30 });
    store.appendSessionSample("session-b", { tokens: 100, cost: 0.001, agents: 2, context: 60 });

    // Then session-a's token buffer has its own values
    const bufferA = store.getSessionBuffer("session-a", "tokens");
    // And session-b's token buffer has its own values
    const bufferB = store.getSessionBuffer("session-b", "tokens");

    expect(bufferA).toBeDefined();
    expect(bufferB).toBeDefined();
    // And the values are independent (not mixed)
    expect(bufferA!.samples).not.toEqual(bufferB!.samples);
  });
});

describe("Removing a session cleans up its per-category buffers", () => {
  it("removed session's buffers are no longer accessible", () => {
    // Given a session with buffered samples
    const store = createMultiSessionStore();
    store.addSession("temp-session");
    store.appendSessionSample("temp-session", { tokens: 200, cost: 0.002, agents: 1, context: 50 });

    // When the session is removed
    store.removeSession("temp-session");

    // Then the session's buffers return undefined
    const buffer = store.getSessionBuffer("temp-session", "tokens");
    expect(buffer).toBeUndefined();
  });
});

describe("Appending to a nonexistent session is a no-op", () => {
  it("no error when appending to unknown session ID", () => {
    // Given an empty store
    const store = createMultiSessionStore();

    // When a sample is appended to a session that does not exist
    // Then no error is thrown
    expect(() => {
      store.appendSessionSample("ghost-session", { tokens: 100, cost: 0, agents: 0, context: 0 });
    }).not.toThrow();

    // And no buffer is created for the unknown session
    const buffer = store.getSessionBuffer("ghost-session", "tokens");
    expect(buffer).toBeUndefined();
  });
});

// ---------------------------------------------------------------------------
// FOCUSED SCENARIOS: Aggregate Buffer Computation
// Traces to: ADR-008 "aggregate ring buffers", ADR-009
// ---------------------------------------------------------------------------

describe("Aggregate token buffer sums across all sessions", () => {
  it("aggregate token value equals sum of per-session token rates", () => {
    // Given 3 sessions with known token rates
    const store = createMultiSessionStore();
    store.addSession("s1");
    store.addSession("s2");
    store.addSession("s3");

    store.appendSessionSample("s1", { tokens: 312, cost: 0.003, agents: 1, context: 45 });
    store.appendSessionSample("s2", { tokens: 185, cost: 0.002, agents: 2, context: 67 });
    store.appendSessionSample("s3", { tokens: 30, cost: 0.0003, agents: 1, context: 20 });

    // When the aggregate token buffer is read
    const aggBuffer = store.getAggregateBuffer("tokens");

    // Then the aggregate value is the sum (312 + 185 + 30 = 527)
    expect(aggBuffer).toBeDefined();
    const latestSample = aggBuffer!.samples[aggBuffer!.samples.length - 1];
    expect(latestSample).toBeDefined();
    // The aggregate sample value equals the sum: 312 + 185 + 30 = 527
    expect(latestSample.tokenRate).toBe(527);
  });
});

describe("Aggregate cost buffer sums across all sessions", () => {
  it("aggregate cost value equals sum of per-session cost rates", () => {
    // Given 2 sessions with known cost rates
    const store = createMultiSessionStore();
    store.addSession("opus-session");
    store.addSession("sonnet-session");

    store.appendSessionSample("opus-session", { tokens: 300, cost: 0.18, agents: 1, context: 40 });
    store.appendSessionSample("sonnet-session", { tokens: 100, cost: 0.004, agents: 1, context: 30 });

    // When the aggregate cost buffer is read
    const aggBuffer = store.getAggregateBuffer("cost");

    // Then the aggregate cost value equals the sum: 0.18 + 0.004 = 0.184
    // (category value stored in tokenRate field -- see multiSessionStore convention)
    expect(aggBuffer).toBeDefined();
    expect(aggBuffer!.samples.length).toBeGreaterThan(0);
    const latestSample = aggBuffer!.samples[aggBuffer!.samples.length - 1];
    expect(latestSample.tokenRate).toBeCloseTo(0.184);
  });
});

describe("Context category has no aggregate buffer", () => {
  it("aggregate context buffer is empty or not populated", () => {
    // Given multiple sessions with context data
    const store = createMultiSessionStore();
    store.addSession("s1");
    store.addSession("s2");

    store.appendSessionSample("s1", { tokens: 100, cost: 0.001, agents: 1, context: 45 });
    store.appendSessionSample("s2", { tokens: 200, cost: 0.002, agents: 1, context: 72 });

    // When the aggregate context buffer is requested
    const aggBuffer = store.getAggregateBuffer("context");

    // Then the buffer is empty (context aggregation is not applicable per ADR-009)
    expect(aggBuffer.samples).toHaveLength(0);
  });
});

// ---------------------------------------------------------------------------
// FOCUSED SCENARIOS: Subscriber Notification
// Traces to: data-models.md "subscribe(callback)"
// ---------------------------------------------------------------------------

describe("Subscribers are notified when samples are appended", () => {
  it("callback invoked after appendSessionSample", () => {
    // Given a store with a subscriber
    const store = createMultiSessionStore();
    store.addSession("test-session");

    let notified = false;
    const unsubscribe = store.subscribe(() => { notified = true; });

    // When a sample is appended
    store.appendSessionSample("test-session", { tokens: 100, cost: 0, agents: 1, context: 50 });

    // Then the subscriber is notified
    expect(notified).toBe(true);

    // Cleanup
    unsubscribe();
  });
});

describe("Unsubscribed callbacks are not invoked", () => {
  it("callback not called after unsubscribe", () => {
    // Given a store with a subscriber that has been unsubscribed
    const store = createMultiSessionStore();
    store.addSession("test-session");

    let callCount = 0;
    const unsubscribe = store.subscribe(() => { callCount += 1; });
    unsubscribe();

    // When a sample is appended
    store.appendSessionSample("test-session", { tokens: 100, cost: 0, agents: 1, context: 50 });

    // Then the callback was not called
    expect(callCount).toBe(0);
  });
});

// ---------------------------------------------------------------------------
// FOCUSED SCENARIOS: Backward Compatibility
// Traces to: architecture-design.md "Backward Compatibility"
// ---------------------------------------------------------------------------

describe("Existing store operations unchanged after extension", () => {
  it("addSession, removeSession, updateSession, getSessions, getSession still work", () => {
    // Given the extended multi-session store
    const store = createMultiSessionStore();

    // When using the original v1 interface
    store.addSession("compat-test");
    const session = store.getSession("compat-test");

    // Then sessions are trackable via the original interface
    expect(session).toBeDefined();
    expect(session!.sessionId).toBe("compat-test");

    // And getSessions returns all tracked sessions
    const all = store.getSessions();
    expect(all).toHaveLength(1);
  });
});

// ---------------------------------------------------------------------------
// ERROR SCENARIOS: Buffer Boundary Conditions
// ---------------------------------------------------------------------------

describe("Getting buffer for unknown category returns empty buffer", () => {
  it("unknown category ID returns empty or undefined buffer", () => {
    // Given a session with samples
    const store = createMultiSessionStore();
    store.addSession("test");
    store.appendSessionSample("test", { tokens: 100, cost: 0, agents: 1, context: 50 });

    // When requesting a buffer for an unknown category
    const buffer = store.getSessionBuffer("test", "nonexistent" as MetricCategoryId);

    // Then no buffer data is returned
    expect(buffer).toBeUndefined();
  });
});

describe("Adding same session twice is idempotent", () => {
  it("duplicate addSession does not reset existing buffers", () => {
    // Given a session with existing sample data
    const store = createMultiSessionStore();
    store.addSession("dup-test");
    store.appendSessionSample("dup-test", { tokens: 500, cost: 0.005, agents: 2, context: 60 });

    // When addSession is called again with the same ID
    store.addSession("dup-test");

    // Then the existing buffer data is preserved (not reset)
    const buffer = store.getSessionBuffer("dup-test", "tokens");
    expect(buffer).toBeDefined();
    expect(buffer!.samples.length).toBeGreaterThan(0);
  });
});

describe("Aggregate buffer updates when a session is removed", () => {
  it("aggregate recalculates after session removal", () => {
    // Given 2 sessions contributing to aggregate
    const store = createMultiSessionStore();
    store.addSession("keep");
    store.addSession("remove");
    store.appendSessionSample("keep", { tokens: 300, cost: 0.003, agents: 1, context: 40 });
    store.appendSessionSample("remove", { tokens: 200, cost: 0.002, agents: 1, context: 50 });

    // When one session is removed
    store.removeSession("remove");

    // Then the aggregate buffer no longer includes the removed session's data
    // (next append to remaining session should produce correct aggregate)
    store.appendSessionSample("keep", { tokens: 350, cost: 0.003, agents: 1, context: 42 });
    const aggBuffer = store.getAggregateBuffer("tokens");
    expect(aggBuffer).toBeDefined();
  });
});

describe("Multiple rapid samples accumulate in ring buffer", () => {
  it("consecutive appends increase buffer sample count", () => {
    // Given a session receiving rapid event updates
    const store = createMultiSessionStore();
    store.addSession("rapid");

    // When 5 samples are appended
    for (let i = 0; i < 5; i++) {
      store.appendSessionSample("rapid", { tokens: 100 + i * 10, cost: 0.001, agents: 1, context: 40 });
    }

    // Then the buffer contains the samples
    const buffer = store.getSessionBuffer("rapid", "tokens");
    expect(buffer).toBeDefined();
    expect(buffer!.samples.length).toBe(5);
  });
});

// ---------------------------------------------------------------------------
// PROPERTY-SHAPED SCENARIOS
// Traces to: ADR-009 -- context never aggregated
// ---------------------------------------------------------------------------

describe("@property: context aggregate buffer is never populated regardless of session count", () => {
  it("for any number of sessions, context aggregate remains empty", () => {
    // Given varying numbers of sessions (1 through 5)
    const store = createMultiSessionStore();
    for (let i = 1; i <= 5; i++) {
      store.addSession(`session-${i}`);
      store.appendSessionSample(`session-${i}`, {
        tokens: 100 * i,
        cost: 0.001 * i,
        agents: i,
        context: 20 * i,
      });

      // When the context aggregate buffer is checked after each addition
      const aggBuffer = store.getAggregateBuffer("context");

      // Then the context aggregate buffer is always empty
      expect(aggBuffer.samples).toHaveLength(0);
    }
  });
});

describe("@property: aggregate sum always equals sum of per-session latest values", () => {
  it("tokens aggregate latest value equals sum of per-session latest values", () => {
    // Given 3 sessions with known token rates
    const store = createMultiSessionStore();
    const rates = [312, 185, 30];
    for (let i = 0; i < rates.length; i++) {
      store.addSession(`s${i}`);
      store.appendSessionSample(`s${i}`, { tokens: rates[i], cost: 0, agents: 1, context: 0 });
    }

    // When the aggregate tokens buffer is read
    const aggBuffer = store.getAggregateBuffer("tokens");

    // Then the aggregate sum invariant holds: aggregate equals sum of per-session latest values
    expect(aggBuffer).toBeDefined();
    expect(aggBuffer!.samples.length).toBeGreaterThan(0);
    const expectedSum = rates.reduce((sum, r) => sum + r, 0);
    expect(aggBuffer!.samples[aggBuffer!.samples.length - 1].tokenRate).toBe(expectedSum);
  });
});

// ---------------------------------------------------------------------------
// STEP 02-02: Hook processor feeds category samples to MultiSessionStore
// Traces to: architecture-design.md "hookProcessor -> appendSessionSample"
// ---------------------------------------------------------------------------

describe("Hook processor feeds per-category samples after metrics update", () => {
  // Helper: create a hook processor with spy appendSessionSample
  const createTestProcessor = () => {
    // Mutable session metrics store (spy for updateMultiSessionMetrics)
    const sessionMetrics = new Map<string, SessionMetrics>();
    const appendedSamples: Array<{ sessionId: string; samples: CategorySampleInput }> = [];

    const deps: HookProcessorDeps = {
      updateMetrics: () => {}, // single-session pipeline -- no-op for these tests
      updateMultiSessionMetrics: (sessionId, _label, reducer) => {
        const prev = sessionMetrics.get(sessionId) ?? createInitialMetrics(sessionId);
        sessionMetrics.set(sessionId, reducer(prev));
      },
      appendSessionSample: (sessionId, samples) => {
        appendedSamples.push({ sessionId, samples });
      },
      pricingTable: DEFAULT_PRICING_TABLE,
    };

    const processor = createHookProcessor(deps);
    return { processor, appendedSamples, sessionMetrics };
  };

  it("Token rate sample derived from instantaneous rate on event", () => {
    // Given a hook processor wired with appendSessionSample spy
    const { processor, appendedSamples } = createTestProcessor();

    // When a prompt_submit event arrives with token usage for session "s1"
    // First event establishes baseline
    processor({
      session_id: "s1",
      event_type: "prompt_submit",
      payload: {
        usage: { input_tokens: 100, output_tokens: 50, cache_read_tokens: 0, cache_creation_tokens: 0 },
        model: "claude-sonnet-4-20250514",
      },
    });

    // Then appendSessionSample was called with the session ID and a tokens value
    expect(appendedSamples.length).toBeGreaterThanOrEqual(1);
    const lastSample = appendedSamples[appendedSamples.length - 1];
    expect(lastSample.sessionId).toBe("s1");
    // Token rate is derived from instantaneous rate computation (>= 0)
    expect(lastSample.samples.tokens).toBeGreaterThanOrEqual(0);
    expect(typeof lastSample.samples.tokens).toBe("number");
    // Cost rate is also derived from instantaneous rate (>= 0)
    expect(lastSample.samples.cost).toBeGreaterThanOrEqual(0);
    expect(typeof lastSample.samples.cost).toBe("number");
  });

  it("Agent count sample derived from session metrics", () => {
    // Given a hook processor wired with appendSessionSample spy
    const { processor, appendedSamples } = createTestProcessor();

    // When a session_start event arrives (increments activeAgentCount)
    processor({
      session_id: "s2",
      event_type: "session_start",
      payload: {},
    });

    // Then appendSessionSample was called with agents value from updated metrics
    expect(appendedSamples.length).toBeGreaterThanOrEqual(1);
    const lastSample = appendedSamples[appendedSamples.length - 1];
    expect(lastSample.sessionId).toBe("s2");
    // Agent count should be 1 after session_start
    expect(lastSample.samples.agents).toBe(1);
    // Context percentage should also be present (from metrics)
    expect(typeof lastSample.samples.context).toBe("number");
  });

  it("Existing single-session pipeline unchanged after extension", () => {
    // Given a hook processor with both single-session and multi-session callbacks
    let singleSessionUpdated = false;
    const deps: HookProcessorDeps = {
      updateMetrics: () => { singleSessionUpdated = true; },
      updateMultiSessionMetrics: (_sid, _reducer) => {},
      appendSessionSample: (_sid, _samples) => {},
      pricingTable: DEFAULT_PRICING_TABLE,
    };
    const processor = createHookProcessor(deps);

    // When an event arrives
    processor({
      session_id: "s3",
      event_type: "prompt_submit",
      payload: {
        usage: { input_tokens: 50, output_tokens: 25, cache_read_tokens: 0, cache_creation_tokens: 0 },
        model: "claude-sonnet-4-20250514",
      },
    });

    // Then the single-session updateMetrics callback was still invoked
    expect(singleSessionUpdated).toBe(true);
  });
});

