tests/acceptance/pm-chart-reliability/ch.source:
/**
 * Acceptance tests: Chart Data Rendering (pm-chart-reliability)
 *
 * Validates that the Performance Monitor charts display visible, non-empty
 * data whenever active sessions are generating events. Covers the data
 * pipeline from sample append through buffer retrieval to coordinate
 * computation for canvas rendering.
 *
 * Driving ports:
 *   - multiSessionStore (adapter boundary)
 *   - chartRenderer.prepareFilledAreaPoints (domain)
 *   - chartRenderer.prepareSparklinePoints (domain)
 *
 * Traces to: US-PMR-01 acceptance criteria
 */

import { describe, it, expect } from "vitest";

import {
  createMultiSessionStore,
  type MultiSessionStore,
} from "../../../src/plugins/norbert-usage/adapters/multiSessionStore";

import {
  prepareFilledAreaPoints,
  prepareSparklinePoints,
  type FilledAreaPoint,
} from "../../../src/plugins/norbert-usage/domain/chartRenderer";

import type { CanvasDimensions } from "../../../src/plugins/norbert-usage/domain/oscilloscope";

// ---------------------------------------------------------------------------
// Fixtures
// ---------------------------------------------------------------------------

const CHART_DIMENSIONS: CanvasDimensions = {
  width: 400,
  height: 200,
  padding: 10,
};

const SPARKLINE_DIMENSIONS: CanvasDimensions = {
  width: 80,
  height: 20,
  padding: 0,
};

/** Populate a store with a session and append N samples at a given rate. */
const populateSession = (
  store: MultiSessionStore,
  sessionId: string,
  tokenRate: number,
  sampleCount: number,
): void => {
  store.addSession(sessionId);
  for (let i = 0; i < sampleCount; i++) {
    store.appendSessionSample(sessionId, {
      tokens: tokenRate,
      cost: tokenRate * 0.001,
      agents: 1,
      context: 40,
    });
  }
};

/** Convert buffer samples to chart-compatible format. */
const toChartSamples = (
  samples: ReadonlyArray<{ timestamp: number; tokenRate: number }>,
): ReadonlyArray<{ timestamp: number; value: number }> =>
  samples.map((s) => ({ timestamp: s.timestamp, value: s.tokenRate }));

// ---------------------------------------------------------------------------
// WALKING SKELETON: Raj sees chart data for active sessions
// Traces to: US-PMR-01 AC1, AC2
// ---------------------------------------------------------------------------

describe("Raj sees a visible chart line when sessions are generating data", () => {
  it("aggregate chart has renderable points when 3 sessions are active", () => {
    // Given Raj has 3 active Claude Code sessions generating token events
    const store = createMultiSessionStore();
    populateSession(store, "refactor-abc1", 420, 15);
    populateSession(store, "tests-def2", 310, 15);
    populateSession(store, "chat-ghi3", 110, 15);

    // When the aggregate token buffer is retrieved and mapped to chart points
    const aggBuffer = store.getAggregateBuffer("tokens");
    const chartSamples = toChartSamples(aggBuffer.samples);
    const points = prepareFilledAreaPoints(chartSamples, CHART_DIMENSIONS, 1000);

    // Then the chart has at least 10 visible data points
    expect(points.length).toBeGreaterThanOrEqual(10);

    // And all points have finite canvas coordinates (no NaN, no blank chart)
    for (const point of points) {
      expect(Number.isFinite(point.x)).toBe(true);
      expect(Number.isFinite(point.y)).toBe(true);
    }

    // And at least one point is above the baseline (non-zero data visible)
    const bottomY = CHART_DIMENSIONS.height - CHART_DIMENSIONS.padding;
    const hasVisibleData = points.some((p) => p.y < bottomY);
    expect(hasVisibleData).toBe(true);
  });
});

// ---------------------------------------------------------------------------
// FOCUSED SCENARIOS: Aggregate buffer content
// Traces to: US-PMR-01 AC1
// ---------------------------------------------------------------------------

describe("Aggregate chart reflects combined token rate across sessions", () => {
  it("aggregate buffer latest value equals sum of per-session rates", () => {
    // Given 3 sessions with known token rates: 420, 310, 110
    const store = createMultiSessionStore();
    store.addSession("s1");
    store.addSession("s2");
    store.addSession("s3");
    store.appendSessionSample("s1", { tokens: 420, cost: 0.42, agents: 1, context: 30 });
    store.appendSessionSample("s2", { tokens: 310, cost: 0.31, agents: 1, context: 50 });
    store.appendSessionSample("s3", { tokens: 110, cost: 0.11, agents: 1, context: 25 });

    // When the aggregate token buffer is read
    const aggBuffer = store.getAggregateBuffer("tokens");
    const latestSample = aggBuffer.samples[aggBuffer.samples.length - 1];

    // Then the aggregate value is 840 (420 + 310 + 110)
    expect(latestSample.tokenRate).toBe(840);
  });
});

// ---------------------------------------------------------------------------
// FOCUSED SCENARIOS: Per-session mini charts
// Traces to: US-PMR-01 AC3
// ---------------------------------------------------------------------------

describe("Per-session mini charts show individual session data", () => {
  it("each session buffer produces sparkline points with non-zero amplitude", () => {
    // Given 3 sessions with rates 420, 310, 110
    const store = createMultiSessionStore();
    populateSession(store, "refactor-abc1", 420, 10);
    populateSession(store, "tests-def2", 310, 10);
    populateSession(store, "chat-ghi3", 110, 10);

    // When sparkline points are prepared for each session
    const sessions = ["refactor-abc1", "tests-def2", "chat-ghi3"];
    for (const sessionId of sessions) {
      const buffer = store.getSessionBuffer(sessionId, "tokens");
      expect(buffer).toBeDefined();
      const chartSamples = toChartSamples(buffer!.samples);
      const points = prepareSparklinePoints(chartSamples, SPARKLINE_DIMENSIONS, 500);

      // Then each session has renderable sparkline points
      expect(points.length).toBeGreaterThan(0);
    }
  });

  it("higher-rate session produces higher amplitude sparkline than lower-rate session", () => {
    // Given refactor-abc1 at 420 tok/s and chat-ghi3 at 110 tok/s
    const store = createMultiSessionStore();
    populateSession(store, "refactor-abc1", 420, 10);
    populateSession(store, "chat-ghi3", 110, 10);

    // When sparkline points are prepared with the same yMax
    const yMax = 500;
    const bufferHigh = store.getSessionBuffer("refactor-abc1", "tokens")!;
    const bufferLow = store.getSessionBuffer("chat-ghi3", "tokens")!;
    const pointsHigh = prepareSparklinePoints(toChartSamples(bufferHigh.samples), SPARKLINE_DIMENSIONS, yMax);
    const pointsLow = prepareSparklinePoints(toChartSamples(bufferLow.samples), SPARKLINE_DIMENSIONS, yMax);

    // Then the high-rate session has lower Y values (higher on canvas = lower Y)
    const avgYHigh = pointsHigh.reduce((sum, p) => sum + p.y, 0) / pointsHigh.length;
    const avgYLow = pointsLow.reduce((sum, p) => sum + p.y, 0) / pointsLow.length;
    expect(avgYHigh).toBeLessThan(avgYLow);
  });
});

// ---------------------------------------------------------------------------
// FOCUSED SCENARIOS: Chart line advances over time
// Traces to: US-PMR-01 AC2
// ---------------------------------------------------------------------------

describe("Chart line extends rightward as new samples arrive", () => {
  it("appending samples increases the number of chart points", () => {
    // Given a session with 5 initial samples
    const store = createMultiSessionStore();
    populateSession(store, "advancing", 300, 5);
    const initialBuffer = store.getAggregateBuffer("tokens");
    const initialPointCount = initialBuffer.samples.length;

    // When 5 more seconds of events arrive
    for (let i = 0; i < 5; i++) {
      store.appendSessionSample("advancing", { tokens: 300, cost: 0.3, agents: 1, context: 40 });
    }

    // Then the buffer has grown with new data points
    const updatedBuffer = store.getAggregateBuffer("tokens");
    expect(updatedBuffer.samples.length).toBeGreaterThan(initialPointCount);

    // And the rightmost point has a more recent timestamp
    const lastInitial = initialBuffer.samples[initialBuffer.samples.length - 1];
    const lastUpdated = updatedBuffer.samples[updatedBuffer.samples.length - 1];
    expect(lastUpdated.timestamp).toBeGreaterThanOrEqual(lastInitial.timestamp);
  });
});

// ---------------------------------------------------------------------------
// FOCUSED SCENARIOS: Session lifecycle
// Traces to: US-PMR-01 AC5
// ---------------------------------------------------------------------------

describe("Chart continues after a session ends", () => {
  it("removing a session leaves remaining sessions contributing to aggregate", () => {
    // Given 3 active sessions contributing to aggregate
    const store = createMultiSessionStore();
    populateSession(store, "keep-a", 420, 5);
    populateSession(store, "keep-b", 310, 5);
    populateSession(store, "ending", 110, 5);

    // When the "ending" session completes and is removed
    store.removeSession("ending");

    // And new data arrives from the remaining 2 sessions
    store.appendSessionSample("keep-a", { tokens: 420, cost: 0.42, agents: 1, context: 30 });
    store.appendSessionSample("keep-b", { tokens: 310, cost: 0.31, agents: 1, context: 50 });

    // Then the aggregate reflects only the 2 remaining sessions (420 + 310 = 730)
    const aggBuffer = store.getAggregateBuffer("tokens");
    const latestSample = aggBuffer.samples[aggBuffer.samples.length - 1];
    expect(latestSample.tokenRate).toBe(730);
  });

  it("removed session no longer appears in per-session buffer lookups", () => {
    // Given a session that has ended
    const store = createMultiSessionStore();
    populateSession(store, "ended-session", 200, 5);
    store.removeSession("ended-session");

    // When per-session buffer is requested
    const buffer = store.getSessionBuffer("ended-session", "tokens");

    // Then no buffer is returned for the ended session
    expect(buffer).toBeUndefined();
  });
});

// ---------------------------------------------------------------------------
// ERROR/BOUNDARY SCENARIOS: Empty state
// Traces to: US-PMR-01 AC4
// ---------------------------------------------------------------------------

describe("Empty state when no sessions are active", () => {
  it("aggregate buffer has no samples when no sessions exist", () => {
    // Given Raj has no active Claude Code sessions
    const store = createMultiSessionStore();

    // When the aggregate token buffer is retrieved
    const aggBuffer = store.getAggregateBuffer("tokens");

    // Then no samples are available
    expect(aggBuffer.samples).toHaveLength(0);
  });

  it("chart point preparation returns empty array for zero samples", () => {
    // Given no sample data
    const emptySamples: ReadonlyArray<{ timestamp: number; value: number }> = [];

    // When chart points are prepared
    const points = prepareFilledAreaPoints(emptySamples, CHART_DIMENSIONS, 1000);

    // Then no chart points are produced (triggers empty-state display)
    expect(points).toHaveLength(0);
  });
});

// ---------------------------------------------------------------------------
// ERROR/BOUNDARY SCENARIOS: Data pipeline edge cases
// Traces to: US-PMR-01 AC6
// ---------------------------------------------------------------------------

describe("Chart handles maximum buffer size without data corruption", () => {
  it("buffer at capacity evicts oldest while maintaining renderable points", () => {
    // Given a session that has been running long enough to fill the buffer
    const store = createMultiSessionStore();
    store.addSession("long-running");

    // When 70 samples are appended (exceeds DEFAULT_BUFFER_CAPACITY=60)
    for (let i = 0; i < 70; i++) {
      store.appendSessionSample("long-running", {
        tokens: 100 + (i % 50),
        cost: 0.01,
        agents: 1,
        context: 40,
      });
    }

    // Then the buffer has exactly capacity samples (oldest evicted)
    const buffer = store.getSessionBuffer("long-running", "tokens");
    expect(buffer).toBeDefined();
    expect(buffer!.samples.length).toBeLessThanOrEqual(60);
    expect(buffer!.samples.length).toBeGreaterThan(0);

    // And chart points can be rendered from the capped buffer
    const chartSamples = toChartSamples(buffer!.samples);
    const points = prepareFilledAreaPoints(chartSamples, CHART_DIMENSIONS, 200);
    expect(points.length).toBeGreaterThan(0);
    for (const point of points) {
      expect(Number.isFinite(point.x)).toBe(true);
      expect(Number.isFinite(point.y)).toBe(true);
    }
  });
});

describe("Chart renders correctly with single data point", () => {
  it("one sample produces one chart point at a valid position", () => {
    // Given a session with exactly one event
    const store = createMultiSessionStore();
    store.addSession("single-event");
    store.appendSessionSample("single-event", { tokens: 500, cost: 0.5, agents: 1, context: 60 });

    // When chart points are prepared
    const buffer = store.getSessionBuffer("single-event", "tokens")!;
    const chartSamples = toChartSamples(buffer.samples);
    const points = prepareFilledAreaPoints(chartSamples, CHART_DIMENSIONS, 1000);

    // Then exactly 1 point is produced with valid coordinates
    expect(points).toHaveLength(1);
    expect(Number.isFinite(points[0].x)).toBe(true);
    expect(Number.isFinite(points[0].y)).toBe(true);
  });
});

describe("All zero token rates produce flat baseline, not blank chart", () => {
  it("zero-rate samples create points at the bottom of the chart", () => {
    // Given sessions generating zero tokens (idle state)
    const store = createMultiSessionStore();
    populateSession(store, "idle-session", 0, 10);

    // When chart points are prepared
    const buffer = store.getSessionBuffer("idle-session", "tokens")!;
    const chartSamples = toChartSamples(buffer.samples);
    const points = prepareFilledAreaPoints(chartSamples, CHART_DIMENSIONS, 1000);

    // Then all points are at the bottom baseline (chart is not blank)
    expect(points.length).toBe(10);
    const bottomY = CHART_DIMENSIONS.height - CHART_DIMENSIONS.padding;
    for (const point of points) {
      expect(point.y).toBe(bottomY);
    }
  });
});

// ---------------------------------------------------------------------------
// ERROR SCENARIO: Appending to nonexistent session
// ---------------------------------------------------------------------------

describe("Appending data to a session that does not exist is safe", () => {
  it("no crash or data corruption when session ID is unknown", () => {
    // Given a store with no sessions
    const store = createMultiSessionStore();

    // When data is appended to a nonexistent session
    expect(() => {
      store.appendSessionSample("phantom", { tokens: 999, cost: 0.9, agents: 1, context: 100 });
    }).not.toThrow();

    // Then no buffer is created for the phantom session
    expect(store.getSessionBuffer("phantom", "tokens")).toBeUndefined();

    // And the aggregate buffer is unaffected
    expect(store.getAggregateBuffer("tokens").samples).toHaveLength(0);
  });
});

// ---------------------------------------------------------------------------
// PROPERTY-SHAPED SCENARIO
// Traces to: US-PMR-01 "non-empty buffer whenever sessions have events"
// ---------------------------------------------------------------------------

describe("@property: aggregate buffer is non-empty whenever active sessions have events", () => {
  it("for any combination of 1-5 sessions with events, aggregate has samples", () => {
    for (let sessionCount = 1; sessionCount <= 5; sessionCount++) {
      // Given N active sessions each with at least one event
      const store = createMultiSessionStore();
      for (let i = 0; i < sessionCount; i++) {
        store.addSession(`session-${i}`);
        store.appendSessionSample(`session-${i}`, {
          tokens: 100 * (i + 1),
          cost: 0.01 * (i + 1),
          agents: 1,
          context: 20 + i * 10,
        });
      }

      // Then the aggregate token buffer is always non-empty
      const aggBuffer = store.getAggregateBuffer("tokens");
      expect(aggBuffer.samples.length).toBeGreaterThan(0);
    }
  });
});

tests/acceptance/norbert-usage/plugin-re.source:
/**
 * Acceptance tests: norbert-usage Plugin Registration and Lifecycle (US-001)
 *
 * Validates that norbert-usage registers its views, tab, status item,
 * and hook processor via the NorbertPlugin API during onLoad, and
 * cleans up during onUnload.
 *
 * Driving ports: loadPlugins, createPluginRegistry, createNorbertAPI
 * Domain: plugin entry point (NorbertPlugin interface)
 *
 * Traces to: US-001 acceptance criteria
 */

import { describe, it, expect, beforeEach } from "vitest";
import { loadPlugins } from "../../../src/plugins/lifecycleManager";
import { createNorbertAPI } from "../../../src/plugins/apiFactory";
import {
  createPluginRegistry,
  getViewsByPlugin,
  getTabsByPlugin,
  getStatusItemsByPlugin,
  getHookRegistrationsByPlugin,
} from "../../../src/plugins/pluginRegistry";
import { resetHookBridge } from "../../../src/plugins/hookBridge";
import { norbertUsagePlugin } from "../../../src/plugins/norbert-usage/index";

beforeEach(() => {
  resetHookBridge();
});

const loadUsagePlugin = () =>
  loadPlugins(
    [norbertUsagePlugin],
    createPluginRegistry(),
    createNorbertAPI
  );

// ---------------------------------------------------------------------------
// WALKING SKELETON
// ---------------------------------------------------------------------------

// @walking_skeleton
describe("User sees Usage tab after norbert-usage loads", () => {
  it("plugin registers views, tab, status item, and hook processor on load", () => {
    // Given the norbert-usage plugin implements the NorbertPlugin interface
    // And the manifest declares id "norbert-usage" with no plugin dependencies
    expect(norbertUsagePlugin.manifest.id).toBe("norbert-usage");
    expect(norbertUsagePlugin.manifest.dependencies).toEqual({});

    // When the plugin system loads norbert-usage
    const registry = loadUsagePlugin();

    // Then the plugin is loaded successfully
    expect(registry.loadedPluginIds).toContain("norbert-usage");

    // And 4 views are registered: gauge-cluster, usage-dashboard, session-dashboard, performance-monitor
    const views = getViewsByPlugin(registry, "norbert-usage");
    expect(views).toHaveLength(4);
    const viewIds = views.map((v) => v.id);
    expect(viewIds).toContain("gauge-cluster");
    expect(viewIds).toContain("usage-dashboard");
    expect(viewIds).toContain("session-dashboard");
    expect(viewIds).toContain("performance-monitor");

    // And a sidebar tab "usage" is registered
    const tabs = getTabsByPlugin(registry, "norbert-usage");
    expect(tabs).toHaveLength(1);
    expect(tabs[0].id).toBe("usage");
    expect(tabs[0].label).toBe("Usage");

    // And a status bar item "cost-ticker" is registered on the right
    const statusItems = getStatusItemsByPlugin(registry, "norbert-usage");
    expect(statusItems).toHaveLength(1);
    expect(statusItems[0].id).toBe("cost-ticker");
    expect(statusItems[0].position).toBe("right");

    // And a hook processor is registered for session events
    const hooks = getHookRegistrationsByPlugin(registry, "norbert-usage");
    expect(hooks.length).toBeGreaterThanOrEqual(1);
    expect(hooks.some((h) => h.hookName === "session-event")).toBe(true);
  });
});

// ---------------------------------------------------------------------------
// FOCUSED SCENARIOS: View Registration Details
// ---------------------------------------------------------------------------

describe("Gauge Cluster view supports floating panel mode", () => {
  it("registers with floatMetric for session cost pill display", () => {
    // Given norbert-usage is loaded
    const registry = loadUsagePlugin();

    // When inspecting the gauge-cluster view registration
    const views = getViewsByPlugin(registry, "norbert-usage");
    const gaugeCluster = views.find((v) => v.id === "gauge-cluster");

    // Then the gauge-cluster view registers with floatMetric "session_cost"
    expect(gaugeCluster).toBeDefined();
    expect(gaugeCluster!.floatMetric).toBe("session_cost");
    // And it is not the primary view
    expect(gaugeCluster!.primaryView).toBe(false);
  });
});

describe("Usage Dashboard is the primary view", () => {
  it("usage-dashboard registers as primaryView for default display", () => {
    // Given norbert-usage is loaded
    const registry = loadUsagePlugin();

    // When inspecting the usage-dashboard view registration
    const views = getViewsByPlugin(registry, "norbert-usage");
    const dashboard = views.find((v) => v.id === "usage-dashboard");

    // Then the usage-dashboard view is marked as primary
    expect(dashboard).toBeDefined();
    expect(dashboard!.primaryView).toBe(true);
    expect(dashboard!.label).toBe("Usage Dashboard");
  });
});

// ---------------------------------------------------------------------------
// ERROR / BOUNDARY SCENARIOS
// ---------------------------------------------------------------------------

describe("Plugin operates with degraded functionality when API unavailable", () => {
  it("continues with views and tab when status item registration fails", () => {
    // Given Norbert core does not support registerStatusItem
    // (simulated by providing a modified API factory that throws on registerStatusItem)

    // When norbert-usage attempts to register all components
    // Then it should not crash -- the plugin should handle partial API availability

    // This test validates the plugin's resilience to partial API support.
    // The plugin should log a warning and continue operating with views and tab
    // even if the status item registration is unavailable.

    // For now, we verify the plugin loads without error through the standard path.
    // The degradation behavior will be tested once the plugin implementation exists.
    const registry = loadUsagePlugin();

    // Then the plugin is loaded
    expect(registry.loadedPluginIds).toContain("norbert-usage");

    // And views are still registered
    const views = getViewsByPlugin(registry, "norbert-usage");
    expect(views.length).toBeGreaterThanOrEqual(3);
  });
});

describe("Plugin uses only public NorbertPlugin API", () => {
  it("norbert-usage imports no internal Norbert modules", () => {
    // Given norbert-usage source code exists
    // When inspecting its imports
    // Then it imports only from ../types (plugin types) and its own domain modules

    // This is a structural test that verifies hexagonal boundary compliance.
    // The plugin must not import from pluginLoader, lifecycleManager, apiFactory,
    // sandboxEnforcer, hookBridge, pluginRegistry, or dependencyResolver.
    const fs = require("fs");
    const path = require("path");
    const pluginDir = path.resolve(
      __dirname,
      "../../../src/plugins/norbert-usage"
    );
    const pluginFiles = fs
      .readdirSync(pluginDir)
      .filter((f: string) => f.endsWith(".ts") || f.endsWith(".tsx"));

    for (const file of pluginFiles) {
      const content = fs.readFileSync(
        path.join(pluginDir, file),
        "utf-8"
      );
      const importLines = content.match(/^import .+ from .+$/gm) ?? [];
      for (const importLine of importLines) {
        const importPathMatch = importLine.match(/from\s+["'](.+?)["']/);
        if (importPathMatch) {
          const importPath = importPathMatch[1];
          expect(importPath).not.toContain("@tauri-apps");
          expect(importPath).not.toMatch(
            /\.\.\/(pluginLoader|lifecycleManager|apiFactory|sandboxEnforcer|hookBridge|pluginRegistry|dependencyResolver)/
          );
        }
      }
    }
  });
});

tests/acceptance/norbert-performance-mon.source:
/**
 * Acceptance tests: Cross-Session Aggregate Metrics (US-PM-002, US-PM-006)
 *
 * Validates that aggregate metrics are correctly computed from multiple
 * active sessions: total tokens/s, total cost/min, active agent counts,
 * and per-session breakdown sorted by rate.
 *
 * Driving ports: pure domain functions (crossSessionAggregator,
 * performanceMonitor chart data composition)
 * These tests exercise the aggregation pipeline, not React views.
 *
 * Traces to: US-PM-002 acceptance criteria, US-PM-006 acceptance criteria
 */

import { describe, it, expect } from "vitest";
import {
  createInitialMetrics,
  type SessionMetrics,
} from "../../../src/plugins/norbert-usage/domain/metricsAggregator";
import {
  aggregateAcrossSessions,
  type AggregateMetrics,
} from "../../../src/plugins/norbert-usage/domain/crossSessionAggregator";

import {
  computeCostRatePerMinute,
  estimateSessionCostRate,
} from "../../../src/plugins/norbert-usage/domain/performanceMonitor";

// ---------------------------------------------------------------------------
// Helper: create session metrics with specific values
// ---------------------------------------------------------------------------

const createSessionSnapshot = (
  overrides: Partial<SessionMetrics> & { sessionId: string },
): SessionMetrics => ({
  ...createInitialMetrics(overrides.sessionId),
  ...overrides,
});

// ---------------------------------------------------------------------------
// WALKING SKELETON: User sees total resource consumption across sessions
// Traces to: US-PM-002, JS-PM-1
// ---------------------------------------------------------------------------

describe("User views aggregate resource consumption across all active sessions", () => {
  it("total token rate equals sum of per-session rates", () => {
    // Given Ravi has 3 active sessions with known token rates
    const sessions: ReadonlyArray<SessionMetrics> = [
      createSessionSnapshot({ sessionId: "refactor-auth", burnRate: 312 }),
      createSessionSnapshot({ sessionId: "migrate-db", burnRate: 185 }),
      createSessionSnapshot({ sessionId: "test-coverage", burnRate: 30 }),
    ];

    // When aggregate metrics are computed across all sessions
    const aggregate = aggregateAcrossSessions(sessions);

    // Then the total tokens/s shows 527 tok/s
    expect(aggregate.totalTokenRate).toBe(527);
    // And the session count is 3
    expect(aggregate.sessionCount).toBe(3);
    // And per-session breakdown lists all 3 sessions
    expect(aggregate.sessions).toHaveLength(3);
  });
});

// ---------------------------------------------------------------------------
// WALKING SKELETON: User sees cost velocity as a leading indicator
// Traces to: US-PM-006, JS-PM-5
// ---------------------------------------------------------------------------

describe("User sees rolling cost rate across all active sessions", () => {
  it("total cost rate reflects sum of per-session cost rates", () => {
    // Given Ravi has sessions with varying cost rates:
    // Opus 4 "refactor-auth" at $0.003/s, Opus 4 "migrate-db" at $0.002/s,
    // Sonnet 4 "test-coverage" at $0.0003/s
    const sessions: ReadonlyArray<SessionMetrics> = [
      createSessionSnapshot({ sessionId: "refactor-auth", burnRate: 312, sessionCost: 5.40 }),
      createSessionSnapshot({ sessionId: "migrate-db", burnRate: 185, sessionCost: 3.20 }),
      createSessionSnapshot({ sessionId: "test-coverage", burnRate: 30, sessionCost: 0.12 }),
    ];

    // When aggregate metrics are computed
    const aggregate = aggregateAcrossSessions(sessions);

    // Then the total cost rate equals the sum of per-session cost rates
    const expectedTotalCostRate = sessions.reduce(
      (sum, s) => sum + estimateSessionCostRate(s),
      0,
    );
    expect(aggregate.totalCostRate).toBeCloseTo(expectedTotalCostRate);
    // And the cost/min display shows the rate in dollars per minute
    const costPerMin = computeCostRatePerMinute(aggregate.totalCostRate);
    const expectedCostPerMin = computeCostRatePerMinute(expectedTotalCostRate);
    expect(costPerMin).toBeCloseTo(expectedCostPerMin);
  });
});

// ---------------------------------------------------------------------------
// FOCUSED SCENARIOS: Aggregate Computation
// Traces to: US-PM-002 AC
// ---------------------------------------------------------------------------

describe("Aggregate token rate is the sum of per-session burn rates", () => {
  it("sums token rates across 3 mixed-model sessions", () => {
    // Given 3 sessions at 312, 185, and 30 tok/s
    const sessions: ReadonlyArray<SessionMetrics> = [
      createSessionSnapshot({ sessionId: "refactor-auth", burnRate: 312 }),
      createSessionSnapshot({ sessionId: "migrate-db", burnRate: 185 }),
      createSessionSnapshot({ sessionId: "test-coverage", burnRate: 30 }),
    ];

    // When aggregate metrics are computed
    const aggregate = aggregateAcrossSessions(sessions);

    // Then the total is 527 tok/s
    expect(aggregate.totalTokenRate).toBe(527);
  });
});

describe("Aggregate active agents is the sum of per-session agent counts", () => {
  it("sums agent counts across sessions", () => {
    // Given 3 sessions with 1, 2, and 1 active agents respectively
    const sessions: ReadonlyArray<SessionMetrics> = [
      createSessionSnapshot({ sessionId: "refactor-auth", activeAgentCount: 1 }),
      createSessionSnapshot({ sessionId: "migrate-db", activeAgentCount: 2 }),
      createSessionSnapshot({ sessionId: "test-coverage", activeAgentCount: 1 }),
    ];

    // When aggregate metrics are computed
    const aggregate = aggregateAcrossSessions(sessions);

    // Then total active agents is 4
    expect(aggregate.totalActiveAgents).toBe(4);
  });
});

describe("Per-session breakdown is sorted by token rate descending", () => {
  it("highest rate session appears first in breakdown", () => {
    // Given 3 sessions with rates 30, 312, and 185 tok/s (unsorted input)
    const sessions: ReadonlyArray<SessionMetrics> = [
      createSessionSnapshot({ sessionId: "test-coverage", burnRate: 30 }),
      createSessionSnapshot({ sessionId: "refactor-auth", burnRate: 312 }),
      createSessionSnapshot({ sessionId: "migrate-db", burnRate: 185 }),
    ];

    // When aggregate metrics are computed
    const aggregate = aggregateAcrossSessions(sessions);

    // Then sessions are listed in order: 312, 185, 30 tok/s
    expect(aggregate.sessions[0].tokenRate).toBe(312);
    expect(aggregate.sessions[1].tokenRate).toBe(185);
    expect(aggregate.sessions[2].tokenRate).toBe(30);
  });
});

// ---------------------------------------------------------------------------
// FOCUSED SCENARIOS: Single Session Edge Case
// Traces to: US-PM-001 scenario 2
// ---------------------------------------------------------------------------

describe("Single session aggregate equals that session's metrics", () => {
  it("aggregate matches the sole session when only one is active", () => {
    // Given Elena has only 1 active session "user-auth" at 280 tok/s
    const sessions: ReadonlyArray<SessionMetrics> = [
      createSessionSnapshot({ sessionId: "user-auth", burnRate: 280, activeAgentCount: 1 }),
    ];

    // When aggregate metrics are computed
    const aggregate = aggregateAcrossSessions(sessions);

    // Then the total tokens/s matches the single session rate
    expect(aggregate.totalTokenRate).toBe(280);
    // And session count is 1
    expect(aggregate.sessionCount).toBe(1);
    // And breakdown shows one row
    expect(aggregate.sessions).toHaveLength(1);
  });
});

// ---------------------------------------------------------------------------
// ERROR SCENARIOS: Empty State
// Traces to: US-PM-001 scenario 3, US-PM-001 AC "Empty state with guidance"
// ---------------------------------------------------------------------------

describe("Empty aggregate when no sessions are active", () => {
  it("all aggregate values are zero with no sessions", () => {
    // Given Marcus has no active Claude Code sessions
    const sessions: ReadonlyArray<SessionMetrics> = [];

    // When aggregate metrics are computed
    const aggregate = aggregateAcrossSessions(sessions);

    // Then all aggregate values are zero
    expect(aggregate.totalTokenRate).toBe(0);
    expect(aggregate.totalCostRate).toBe(0);
    expect(aggregate.totalActiveAgents).toBe(0);
    expect(aggregate.sessionCount).toBe(0);
    // And the breakdown is empty
    expect(aggregate.sessions).toHaveLength(0);
  });
});

// ---------------------------------------------------------------------------
// ERROR SCENARIOS: Session Lifecycle Changes
// Traces to: US-PM-002 AC "New sessions appear", "Ended sessions removed"
// ---------------------------------------------------------------------------

describe("Aggregate updates when a new session is added", () => {
  it("total increases when a session is added to the active set", () => {
    // Given Elena has 2 sessions totaling 400 tok/s
    const existingSessions: ReadonlyArray<SessionMetrics> = [
      createSessionSnapshot({ sessionId: "session-a", burnRate: 250 }),
      createSessionSnapshot({ sessionId: "session-b", burnRate: 150 }),
    ];

    // When a new session "deploy-staging" starts at 80 tok/s
    const updatedSessions: ReadonlyArray<SessionMetrics> = [
      ...existingSessions,
      createSessionSnapshot({ sessionId: "deploy-staging", burnRate: 80 }),
    ];

    // Then the aggregate reflects 3 sessions at 480 tok/s
    const aggregate = aggregateAcrossSessions(updatedSessions);
    expect(aggregate.totalTokenRate).toBe(480);
    expect(aggregate.sessionCount).toBe(3);
  });
});

describe("Aggregate updates when a session ends", () => {
  it("total decreases when a session is removed from the active set", () => {
    // Given Marcus has 3 sessions with total 500 tok/s
    // And session "quick-fix" was contributing 100 tok/s
    const allSessions: ReadonlyArray<SessionMetrics> = [
      createSessionSnapshot({ sessionId: "session-a", burnRate: 250 }),
      createSessionSnapshot({ sessionId: "quick-fix", burnRate: 100 }),
      createSessionSnapshot({ sessionId: "session-c", burnRate: 150 }),
    ];

    // When session "quick-fix" ends (removed from active set)
    const remainingSessions = allSessions.filter(s => s.sessionId !== "quick-fix");

    // Then the total drops to 400 tok/s
    const aggregate = aggregateAcrossSessions(remainingSessions);
    expect(aggregate.totalTokenRate).toBe(400);
    expect(aggregate.sessionCount).toBe(2);
  });
});

// ---------------------------------------------------------------------------
// ERROR SCENARIOS: Cost Rate Edge Cases
// Traces to: US-PM-006 AC "Zero cost correctly displayed during idle"
// ---------------------------------------------------------------------------

describe("Zero cost rate when all sessions are idle", () => {
  it("cost rate is zero when no tokens are being consumed", () => {
    // Given Marcus has 2 sessions running but both agents are idle
    const sessions: ReadonlyArray<SessionMetrics> = [
      createSessionSnapshot({ sessionId: "session-a", burnRate: 0 }),
      createSessionSnapshot({ sessionId: "session-b", burnRate: 0 }),
    ];

    // When aggregate metrics are computed
    const aggregate = aggregateAcrossSessions(sessions);

    // Then the total cost rate is zero
    expect(aggregate.totalCostRate).toBe(0);
    // And the total token rate is zero
    expect(aggregate.totalTokenRate).toBe(0);
    // And cost per minute is also zero
    const costPerMin = computeCostRatePerMinute(aggregate.totalCostRate);
    expect(costPerMin).toBe(0);
  });
});

// ---------------------------------------------------------------------------
// PROPERTY-SHAPED SCENARIOS
// Traces to: Shared Artifacts Registry -- "Aggregate always equals sum of parts"
// ---------------------------------------------------------------------------

describe("@property: aggregate total always equals sum of per-session values", () => {
  it("sum invariant holds for any combination of session metrics", () => {
    // Given any valid set of active sessions with varying metrics
    const sessions: ReadonlyArray<SessionMetrics> = [
      createSessionSnapshot({ sessionId: "s1", burnRate: 100, activeAgentCount: 1 }),
      createSessionSnapshot({ sessionId: "s2", burnRate: 0, activeAgentCount: 2 }),
      createSessionSnapshot({ sessionId: "s3", burnRate: 999, activeAgentCount: 1 }),
      createSessionSnapshot({ sessionId: "s4", burnRate: 1, activeAgentCount: 0 }),
    ];

    // When aggregate metrics are computed
    const aggregate = aggregateAcrossSessions(sessions);

    // Then aggregate totals equal the sum of per-session values
    const expectedTokenRate = sessions.reduce((sum, s) => sum + s.burnRate, 0);
    const expectedAgents = sessions.reduce((sum, s) => sum + s.activeAgentCount, 0);
    expect(aggregate.totalTokenRate).toBe(expectedTokenRate);
    expect(aggregate.totalActiveAgents).toBe(expectedAgents);
  });
});

